type DivProps = React.HTMLAttributes<HTMLDivElement>;
type ButtonProps = React.ButtonHTMLAttributes<HTMLButtonElement> & { variant?: "default" | "secondary" | "outline" };
type InputProps = React.InputHTMLAttributes<HTMLInputElement>;

function Card({ className = "", ...props }: DivProps) {
  return <div className={className} {...props} />;
}

function CardContent({ className = "", ...props }: DivProps) {
  return <div className={className} {...props} />;
}

function Button({ className = "", variant = "default", ...props }: ButtonProps) {
  const variantClass =
    variant === "secondary"
      ? "bg-slate-700 text-slate-100 hover:bg-slate-600"
      : variant === "outline"
        ? "border border-slate-600 bg-transparent text-slate-100 hover:bg-slate-800"
        : "bg-blue-600 text-white hover:bg-blue-500";
  return (
    <button
      className={`inline-flex items-center justify-center rounded-xl px-4 py-2 text-sm font-medium transition disabled:cursor-not-allowed disabled:opacity-50 ${variantClass} ${className}`}
      {...props}
    />
  );
}

function Input({ className = "", ...props }: InputProps) {
  return <input className={`w-full rounded-xl px-3 py-2 outline-none ${className}`} {...props} />;
}

