function buildAdjacency(nodes: NodeT[], edges: [string, string][]) {
  const adj: Record<string, string[]> = Object.fromEntries(nodes.map((n) => [n.id, []]));
  for (const [u, v] of edges) {
    if (adj[u] && adj[v]) {
      adj[u].push(v);
      adj[v].push(u);
    }
  }
  return adj;
}
function getNodeMap(nodes: NodeT[]) { return Object.fromEntries(nodes.map((n) => [n.id, n])) as Record<string, NodeT>; }
function edgeLength(nodeMap: Record<string, NodeT>, fromId: string, toId: string) { const a = nodeMap[fromId]; const b = nodeMap[toId]; return Math.hypot(b.x - a.x, b.y - a.y); }
function toPolar(point: { x: number; y: number }) { const r = Math.hypot(point.x, point.y); let theta = Math.atan2(point.y, point.x); if (theta < 0) theta += 2 * Math.PI; return { r, theta }; }
function angularSeparation(a: number, b: number) { const d = Math.abs(a - b); return Math.min(d, 2 * Math.PI - d); }
function hyperbolicDistance(a: { x: number; y: number }, b: { x: number; y: number }) { const pa = toPolar(a); const pb = toPolar(b); const delta = angularSeparation(pa.theta, pb.theta); const coshX = Math.cosh(pa.r) * Math.cosh(pb.r) - Math.sinh(pa.r) * Math.sinh(pb.r) * Math.cos(delta); return Math.acosh(Math.max(1, coshX)); }
function interpolate(a: NodeT, b: NodeT, t: number) { return { x: a.x + (b.x - a.x) * t, y: a.y + (b.y - a.y) * t }; }
function randomChoice<T>(items: T[]) { return items.length ? items[Math.floor(Math.random() * items.length)] : null; }
function shuffleArray<T>(items: T[]) { const arr = [...items]; for (let i = arr.length - 1; i > 0; i -= 1) { const j = Math.floor(Math.random() * (i + 1)); [arr[i], arr[j]] = [arr[j], arr[i]]; } return arr; }
function bfsDistances(adjacency: Record<string, string[]>, start: string) { const dist: Record<string, number> = { [start]: 0 }; const queue = [start]; while (queue.length) { const u = queue.shift()!; for (const v of adjacency[u] || []) { if (dist[v] === undefined) { dist[v] = dist[u] + 1; queue.push(v); } } } return dist; }
function chooseGhostNeighbor(adjacency: Record<string, string[]>, nodeMap: Record<string, NodeT>, ghostNodeId: string, playerPoint: { x: number; y: number }, p: number) { const options = adjacency[ghostNodeId] || []; if (!options.length) return null; if (Math.random() < p) return randomChoice(options); let best = options[0]; let bestDistance = Number.POSITIVE_INFINITY; for (const option of options) { const d = hyperbolicDistance(nodeMap[option], playerPoint); if (d < bestDistance) { bestDistance = d; best = option; } } return best; }
function chooseInitialGhostNode(nodes: NodeT[], adjacency: Record<string, string[]>, source: string, target: string, blocked = new Set<string>()) { const dist = bfsDistances(adjacency, source); const candidates = nodes.map((n) => n.id).filter((id) => id !== source && id !== target && dist[id] !== undefined && !blocked.has(id)).sort((a, b) => (dist[b] ?? -1) - (dist[a] ?? -1)); if (!candidates.length) return null; const best = dist[candidates[0]] ?? 0; return randomChoice(candidates.filter((id) => (dist[id] ?? -1) >= best - 1)); }
function scoreFromPath(hops: number, shortestDistance: number) { if (hops < shortestDistance) return 0; return Math.max(0, Math.min(100, Math.round((100 * shortestDistance) / hops))); }
function maxAllowedHops(shortestDistance: number, level = 1) { return level >= 5 ? shortestDistance * 3 : shortestDistance * 2; }
function pathToEdgeSet(path: string[]) { const set = new Set<string>(); for (let i = 0; i < path.length - 1; i += 1) set.add(`${path[i]}--${path[i + 1]}`); return set; }
function movementAngle(fromNode?: NodeT | null, toNode?: NodeT | null) { if (!fromNode || !toNode) return 0; return (Math.atan2(toNode.y - fromNode.y, toNode.x - fromNode.x) * 180) / Math.PI; }
function levelProbability(level: number, totalLevels: number) { if (totalLevels <= 1) return 1; const t = (level - 1) / (totalLevels - 1); const curved = Math.pow(t, 0.6); return Math.max(0.1, 1 - 0.9 * curved); }
function ghostCountForLevel(level: number) { if (level > 15) return 4; if (level > 10) return 3; if (level > 5) return 2; return 1; }
function loadLeaderboard(): ScoreEntry[] { if (typeof window === "undefined") return []; try { const raw = window.localStorage.getItem("hyperbolic-network-ranking"); return raw ? JSON.parse(raw) : []; } catch { return []; } }
function saveLeaderboard(entries: ScoreEntry[]) { if (typeof window === "undefined") return; window.localStorage.setItem("hyperbolic-network-ranking", JSON.stringify(entries)); }
function updateLeaderboard(entries: ScoreEntry[], playerName: string, score: number, levelReached: number) { const normalized = playerName.trim().toLowerCase(); const existing = entries.find((entry) => entry.name.trim().toLowerCase() === normalized); let nextEntries: ScoreEntry[]; if (!existing) { nextEntries = [...entries, { name: playerName, score, levelReached, timestamp: Date.now() }]; } else { const shouldUpdate = score > existing.score || (score === existing.score && levelReached > existing.levelReached); nextEntries = entries.map((entry) => entry.name.trim().toLowerCase() !== normalized ? entry : shouldUpdate ? { ...entry, name: playerName, score, levelReached, timestamp: Date.now() } : entry); } const next = nextEntries.sort((a, b) => b.score - a.score || b.levelReached - a.levelReached || a.timestamp - b.timestamp).slice(0, 10); saveLeaderboard(next); return next; }
function validateGraphData(nodes: NodeT[], edges: [string, string][], challenges: Challenge[]) { const nodeIds = new Set(nodes.map((n) => n.id)); const adjacency = buildAdjacency(nodes, edges); const issues: string[] = []; if (nodes.length !== 50) issues.push(`Expected 50 nodes, found ${nodes.length}.`); edges.forEach(([u, v], index) => { if (!nodeIds.has(u) || !nodeIds.has(v)) issues.push(`Edge ${index} references missing node: ${u}-${v}.`); }); challenges.forEach((challenge, index) => { if (!nodeIds.has(challenge.source) || !nodeIds.has(challenge.target)) { issues.push(`Challenge ${index + 1} references a missing node.`); return; } const dist = bfsDistances(adjacency, challenge.source)[challenge.target]; if (dist === undefined) issues.push(`Challenge ${index + 1} is disconnected.`); else if (dist !== challenge.shortestDistance) issues.push(`Challenge ${index + 1} shortest path mismatch: stored ${challenge.shortestDistance}, actual ${dist}.`); }); return issues; }
function poincareFromRaw(point: { x: number; y: number }) { const polar = toPolar(point); const rho = Math.tanh(polar.r / 2); return { x: rho * Math.cos(polar.theta), y: rho * Math.sin(polar.theta) }; }
function rawFromPoincare(point: { x: number; y: number }) { const rho = Math.min(0.999999, Math.hypot(point.x, point.y)); const theta = Math.atan2(point.y, point.x); const r = 2 * Math.atanh(rho); return { x: r * Math.cos(theta), y: r * Math.sin(theta) }; }
function geodesicCircleInPoincare(a: { x: number; y: number }, b: { x: number; y: number }) { const det = a.x * b.y - a.y * b.x; if (Math.abs(det) < 1e-9) return { type: "diameter" as const }; const rhs1 = (a.x * a.x + a.y * a.y + 1) / 2; const rhs2 = (b.x * b.x + b.y * b.y + 1) / 2; const cx = (rhs1 * b.y - rhs2 * a.y) / det; const cy = (a.x * rhs2 - b.x * rhs1) / det; const radius = Math.sqrt(Math.max(0, cx * cx + cy * cy - 1)); return { type: "circle" as const, cx, cy, radius }; }
function sampleGeodesicRaw(sourcePoint: { x: number; y: number }, targetPoint: { x: number; y: number }, samples = 90) { const a = poincareFromRaw(sourcePoint); const b = poincareFromRaw(targetPoint); const circle = geodesicCircleInPoincare(a, b); const points: { x: number; y: number }[] = []; if (circle.type === "diameter") { for (let i = 0; i <= samples; i += 1) { const t = i / samples; points.push(rawFromPoincare({ x: a.x + (b.x - a.x) * t, y: a.y + (b.y - a.y) * t })); } return points; } const a1 = Math.atan2(a.y - circle.cy, a.x - circle.cx); let a2 = Math.atan2(b.y - circle.cy, b.x - circle.cx); let delta = a2 - a1; while (delta <= -Math.PI) delta += 2 * Math.PI; while (delta > Math.PI) delta -= 2 * Math.PI; for (let i = 0; i <= samples; i += 1) { const t = i / samples; const ang = a1 + delta * t; points.push(rawFromPoincare({ x: circle.cx + circle.radius * Math.cos(ang), y: circle.cy + circle.radius * Math.sin(ang) })); } return points; }

